export async function GET(request: Request) {
  const { searchParams } = new URL(request.url)
  const destination = searchParams.get('destination') || ''
  const cityKey = destination.toLowerCase().split(',')[0].trim()

  // 1. Check static DB first (instant response)
  if (STATIC_DB[cityKey]) {
    return NextResponse.json({ items: STATIC_DB[cityKey], source: 'curated' })
  }

  // 2. AI fallback for any city not in static DB (Groq → Gemini cascade)
  const prompt = `You are an expert on Indian regional cuisine and street food.
List 8 must-try street foods or local dishes for a traveler visiting ${destination}, India.

Return ONLY a valid JSON object with this exact structure:
{
  "items": [
    {
      "name": "Food name",
      "location_hint": "Specific stall, market, or area to find it",
      "description": "2 sentences: what it is and why it's special here",
      "price": "₹XX–XX",
      "bestTime": "Morning/Evening/Lunch/etc",
      "spiceLevel": "mild/medium/hot/extra-hot"
    }
  ]
}

Rules:
- Only include real, authentic dishes actually found in ${destination}
- Include a mix of snacks, meals, and drinks
- Be specific about WHERE to find each item (real stall names or market names)
- No beef or buffalo meat`

  const { content, provider } = await callAI({
    prompt,
    systemPrompt: 'You return ONLY valid JSON. No markdown, no explanation.',
    temperature: 0.6,
    maxTokens: 2000,
  })

  if (provider !== 'none' && content) {
    const parsed = parseAIJson(content)
    if (parsed) {
      // Handle both array and object responses
      const items = Array.isArray(parsed) ? parsed : (parsed.items || [])
      return NextResponse.json({ items, source: 'ai' })
    }
  }

  return NextResponse.json({ items: [], source: 'none' })
}
